/*
 * acos() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly acos  (test_acos_opt.elf)
 *   2. Linked with toolchain's default acos       (test_acos_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static volatile double g_acc;

static void emit(double x)
{
#ifdef EN_PERF
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += acos(vx);
#else
    double r = acos(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
#endif
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* ------------------------------------------------------------------ */
/* Representative 100-point test suite                                */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0);                               /* acos(0) = pi/2 */
    emit(-0.0);                              /* acos(-0) = pi/2 */
    emit_u(0x7ff8000000000000ULL);           /* qNaN */
    emit_u(0x7ff0000000000001ULL);           /* sNaN */
    emit_u(0xfff8000000000000ULL);           /* -qNaN */
    emit_u(0x7ff0000000000000ULL);           /* +Inf (domain error -> NaN) */
    emit_u(0xfff0000000000000ULL);           /* -Inf (domain error -> NaN) */

    /* --- Section 2: Subnormal inputs (6) --- */
    /* Subnormals are in (-1,1), so acos is defined; result is very near pi/2 */
    emit_u(0x0000000000000001ULL);           /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);           /* min negative subnormal */
    emit_u(0x0008000000000000ULL);           /* mid positive subnormal */
    emit_u(0x8008000000000000ULL);           /* mid negative subnormal */
    emit_u(0x000fffffffffffffULL);           /* max positive subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL);           /* max negative subnormal */

    /* --- Section 3: Domain boundary: exact +/-1 and out-of-domain inputs (8) --- */
    emit(1.0);                               /* acos(1) = 0 (exact boundary) */
    emit(-1.0);                              /* acos(-1) = pi (exact boundary) */
    emit_u(0x3fefffffffffffffULL);           /* one ULP below 1.0 (inside domain) */
    emit_u(0x3ff0000000000001ULL);           /* one ULP above 1.0 (outside domain -> NaN) */
    emit_u(0xbfefffffffffffffULL);           /* one ULP above -1.0 (inside domain) */
    emit_u(0xbff0000000000001ULL);           /* one ULP below -1.0 (outside domain -> NaN) */
    emit(2.0);                               /* outside domain -> NaN */
    emit(-2.0);                              /* outside domain -> NaN */

    /* --- Section 4: Near 1.0 ULP density (8) --- */
    emit_u(0x3ff0000000000000ULL);           /* 1.0 exactly */
    emit_u(0x3fefffffffffffffULL);           /* 1 ULP below 1.0 */
    emit_u(0x3feffffffffffffeULL);           /* 2 ULPs below 1.0 */
    emit_u(0x3feffffffffffff0ULL);           /* a few ULPs below 1.0 */
    emit_u(0x3fefffffff000000ULL);           /* moderately below 1.0 */
    emit_u(0x3fefffffffbfffffULL);           /* close to 1.0 from below */
    emit_u(0x3feffff000000000ULL);           /* slightly further from 1.0 */
    emit_u(0x3feff80000000000ULL);           /* 1.0 - ~2^-9 */

    /* --- Section 5: Near -1.0 ULP density (6) --- */
    emit_u(0xbff0000000000000ULL);           /* -1.0 exactly */
    emit_u(0xbfefffffffffffffULL);           /* 1 ULP toward zero from -1.0 */
    emit_u(0xbfeffffffffffffeULL);           /* 2 ULPs toward zero from -1.0 */
    emit_u(0xbfeffffffffffff0ULL);           /* a few ULPs toward zero from -1.0 */
    emit_u(0xbfefffffff000000ULL);           /* moderately above -1.0 */
    emit_u(0xbfeff80000000000ULL);           /* -1.0 + ~2^-9 */

    /* --- Section 6: Known mathematical key values (14) --- */
    /* acos(sqrt(3)/2) = pi/6; acos(sqrt(2)/2) = pi/4; acos(0.5) = pi/3; acos(0) = pi/2 */
    emit(0.5);                               /* acos(0.5) = pi/3 = 60 deg */
    emit(-0.5);                              /* acos(-0.5) = 2*pi/3 = 120 deg */
    emit_u(0x3fe6a09e667f3bcdULL);           /* sqrt(2)/2 ~ 0.7071...: acos = pi/4 */
    emit_u(0xbfe6a09e667f3bcdULL);           /* -sqrt(2)/2: acos = 3*pi/4 */
    emit_u(0x3febb67ae8584caaULL);           /* sqrt(3)/2 ~ 0.8660...: acos = pi/6 */
    emit_u(0xbfebb67ae8584caaULL);           /* -sqrt(3)/2: acos = 5*pi/6 */
    emit_u(0x3fe0000000000000ULL);           /* 0.5 in hex */
    emit_u(0x3fd0000000000000ULL);           /* 0.25: acos = ~75.5 deg */
    emit_u(0xbfd0000000000000ULL);           /* -0.25 */
    emit_u(0x3fc0000000000000ULL);           /* 0.125 */
    emit_u(0xbfc0000000000000ULL);           /* -0.125 */
    emit_u(0x3fe921fb54442d18ULL);           /* pi/4 ~ 0.7854 (as input) */
    emit_u(0x3fde147ae147ae14ULL);           /* 0.47: near midpoint of [0,0.5] */
    emit_u(0xbfde147ae147ae14ULL);           /* -0.47 */

    /* --- Section 7: Polynomial transition at |x| = 0.5 (8) --- */
    /* Many acos implementations switch algorithms at |x| = 0.5 */
    emit_u(0x3fe0000000000000ULL);           /* 0.5 exactly */
    emit_u(0xbfe0000000000000ULL);           /* -0.5 exactly */
    emit_u(0x3fdffffffffffffeULL);           /* 1 ULP below 0.5 (just inside lower interval) */
    emit_u(0x3fe0000000000001ULL);           /* 1 ULP above 0.5 (just in upper interval) */
    emit_u(0xbfdffffffffffffeULL);           /* 1 ULP above -0.5 */
    emit_u(0xbfe0000000000001ULL);           /* 1 ULP below -0.5 */
    emit_u(0x3fdfffffffffffffULL);           /* max below 0.5 */
    emit_u(0xbfdfffffffffffffULL);           /* min above -0.5 */

    /* --- Section 8: Exponent boundary inputs (6) --- */
    emit_u(0x3fd0000000000000ULL);           /* 0.25 = 2^-2 */
    emit_u(0x3fc0000000000000ULL);           /* 0.125 = 2^-3 */
    emit_u(0x3fb0000000000000ULL);           /* 0.0625 = 2^-4 */
    emit_u(0xbfd0000000000000ULL);           /* -0.25 */
    emit_u(0xbfc0000000000000ULL);           /* -0.125 */
    emit_u(0xbfb0000000000000ULL);           /* -0.0625 */

    /* --- Section 9: Near-zero small inputs (8) --- */
    /* acos(x) ~ pi/2 - x for tiny x; tests fast-path / Taylor-series branch */
    emit_u(0x3f50000000000000ULL);           /* 2^-10 */
    emit_u(0x3f00000000000000ULL);           /* 2^-15 */
    emit_u(0x3eb0000000000000ULL);           /* 2^-20 */
    emit_u(0x3e50000000000000ULL);           /* 2^-26 (typical fast-path threshold) */
    emit_u(0xbf50000000000000ULL);           /* -2^-10 */
    emit_u(0xbf00000000000000ULL);           /* -2^-15 */
    emit_u(0xbeb0000000000000ULL);           /* -2^-20 */
    emit_u(0xbe50000000000000ULL);           /* -2^-26 */

    /* --- Section 10: Dense interior coverage (29) --- */
    /* Evenly spaced across [-1,1] to stress polynomial branches */
    emit(-0.99);
    emit(-0.95);
    emit(-0.90);
    emit(-0.85);
    emit(-0.80);
    emit(-0.75);
    emit(-0.70);
    emit(-0.60);
    emit(-0.40);
    emit(-0.30);
    emit(-0.20);
    emit(-0.10);
    emit(-0.05);
    emit(-0.01);
    emit(0.01);
    emit(0.05);
    emit(0.10);
    emit(0.20);
    emit(0.30);
    emit(0.40);
    emit(0.60);
    emit(0.70);
    emit(0.75);
    emit(0.80);
    emit(0.85);
    emit(0.90);
    emit(0.95);
    emit(0.99);
    emit_u(0x3fe6666666666666ULL);           /* 0.7: stresses upper-half polynomial */
}

/* ------------------------------------------------------------------ */

#ifndef EN_PERF
/* Sweep [-1, 1] in 200 steps */
static void test_sweep(void)
{
    int nsteps = 200;
    double step = 2.0 / (double)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit(-1.0 + (double)i * step);
}

/* Sample [0, 0.5] every 4503599627370496 ULP (~50 cases) */
static void test_exhaustive_small(void)
{
    uint64_t end = 0x3fe0000000000000ULL; /* 0.5 */
    for (uint64_t b = 0; b <= end; b += 4503599627370496ULL)
        emit_u(b);
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}

